import { useState } from "react"

interface NicheTranscriptProps {
  recipientName: string
  role: string
  course: string
  tier: string
  finalScore: number
  cohortNumber: string
  graduationDate: string
  pillar1Score: number
  pillar2Score: number
  pillar3Score: number
  pillar4Score: number
  pillar1Weighted: number
  pillar2Weighted: number
  pillar3Weighted: number
  pillar4Weighted: number
  trainingType: string
  subPillarScores: { [key: string]: number }
  onClose: () => void
}

const styles = `
  @import url('https://fonts.googleapis.com/css2?family=Cinzel:wght@500;600;700;800&family=Poppins:wght@300;400;500;600&family=Playfair+Display:ital,wght@0,400;0,500;0,600;0,700;0,800;1,400;1,600&display=swap');

  .font-cinzel    { font-family: 'Cinzel', serif; }
  .font-playfair  { font-family: 'Playfair Display', serif; }
  .font-poppins   { font-family: 'Poppins', sans-serif; }

  .transcript-bg {
    background-color: #FAF9F6;
  }
`;

const NicheTranscript: React.FC<NicheTranscriptProps> = ({
  recipientName,
  role,
  course,
  tier,
  finalScore,
  cohortNumber,
  graduationDate,
  pillar1Score,
  pillar2Score,
  pillar3Score,
  pillar4Score,
  pillar1Weighted,
  pillar2Weighted,
  pillar3Weighted,
  pillar4Weighted,
  trainingType,
  subPillarScores,
  onClose
}) => {
  const logoBase64 = "data:image/png;base64,"

  const nannyPillars = [
    { 
      name: 'Childcare & Development', 
      weight: 1.8, 
      maxWeighted: 45,
      subPillars: [
        { name: 'Child Hygiene & Safety', key: 'child_hygiene_safety', maxScore: 5 },
        { name: 'Routine Management', key: 'routine_management', maxScore: 5 },
        { name: 'Behavior Management', key: 'behavior_management', maxScore: 5 },
        { name: 'Potty Training', key: 'potty_training', maxScore: 5 },
        { name: 'First Aid', key: 'first_aid', maxScore: 5 }
      ]
    },
    { 
      name: 'Professional Conduct', 
      weight: 1.2, 
      maxWeighted: 30,
      subPillars: [
        { name: 'Receives Correction', key: 'receives_correction', maxScore: 5 },
        { name: 'Communication', key: 'nanny_communication', maxScore: 5 },
        { name: 'Emotional Control', key: 'emotional_control', maxScore: 5 },
        { name: 'Boundaries & Ethics', key: 'boundaries_ethics', maxScore: 5 },
        { name: 'Reliability', key: 'reliability', maxScore: 5 }
      ]
    },
    { 
      name: 'Housekeeping', 
      weight: 0.6, 
      maxWeighted: 15,
      subPillars: [
        { name: 'Child Room Hygiene', key: 'child_room_hygiene', maxScore: 5 },
        { name: 'Toy Sanitation', key: 'toy_sanitation', maxScore: 5 },
        { name: 'Bathroom Cleanliness', key: 'bathroom_cleanliness', maxScore: 5 },
        { name: 'Daily Reset', key: 'daily_reset', maxScore: 5 },
        { name: 'Laundry Care', key: 'laundry_care', maxScore: 5 }
      ]
    },
    { 
      name: 'Cooking & Nutrition', 
      weight: 0.4, 
      maxWeighted: 10,
      subPillars: [
        { name: 'Child Safe Food Prep', key: 'child_safe_food_prep', maxScore: 5 },
        { name: 'Age Appropriate Meals', key: 'age_appropriate_meals', maxScore: 5 },
        { name: 'Food Allergy Awareness', key: 'food_allergy_awareness', maxScore: 5 },
        { name: 'Kitchen Hygiene & Storage', key: 'kitchen_hygiene_storage', maxScore: 5 },
        { name: 'Family Food Prep', key: 'family_food_prep', maxScore: 5 }
      ]
    }
  ]

  const houseManagerPillars = [
    { 
      name: 'Professional Conduct', 
      weight: 1.2, 
      maxWeighted: 30,
      subPillars: [
        { name: 'Authority & Leadership', key: 'authority_leadership', maxScore: 5 },
        { name: 'Communication', key: 'hm_communication', maxScore: 5 },
        { name: 'Stress Management', key: 'stress_management', maxScore: 5 },
        { name: 'Discretion & Confidentiality', key: 'discretion_confidentiality', maxScore: 5 },
        { name: 'Decision Making', key: 'decision_making', maxScore: 5 }
      ]
    },
    { 
      name: 'Housekeeping & Systems', 
      weight: 1.2, 
      maxWeighted: 30,
      subPillars: [
        { name: 'Cleaning Standards', key: 'cleaning_standards', maxScore: 5 },
        { name: 'Household Routines', key: 'household_routines', maxScore: 5 },
        { name: 'Organization Systems', key: 'organization_systems', maxScore: 5 },
        { name: 'Housekeeping Appliances', key: 'housekeeping_appliances', maxScore: 5 },
        { name: 'Laundry & Ironing', key: 'laundry_ironing', maxScore: 5 }
      ]
    },
    { 
      name: 'Cooking & Kitchen', 
      weight: 1.0, 
      maxWeighted: 25,
      subPillars: [
        { name: 'Kitchen Hygiene & Safety', key: 'kitchen_hygiene_safety', maxScore: 5 },
        { name: 'Meal Planning', key: 'meal_planning', maxScore: 5 },
        { name: 'Food Prep & Presentation', key: 'food_prep_presentation', maxScore: 5 },
        { name: 'Storage System', key: 'storage_system', maxScore: 5 },
        { name: 'Cleaning & Maintenance', key: 'cleaning_maintenance', maxScore: 5 }
      ]
    },
    { 
      name: 'Childcare Literacy', 
      weight: 0.6, 
      maxWeighted: 15,
      subPillars: [
        { name: 'Child Development Knowledge', key: 'child_development_knowledge', maxScore: 5 },
        { name: 'Routine Understanding', key: 'routine_understanding', maxScore: 5 },
        { name: 'Nanny Coordination', key: 'nanny_coordination', maxScore: 5 },
        { name: 'Role Boundaries', key: 'role_boundaries', maxScore: 5 },
        { name: 'Safety Awareness', key: 'safety_awareness', maxScore: 5 }
      ]
    }
  ]

  const pillars = trainingType === 'nanny' ? nannyPillars : houseManagerPillars
  const pillarScores = [pillar1Score, pillar2Score, pillar3Score, pillar4Score]
  const weightedScores = [pillar1Weighted, pillar2Weighted, pillar3Weighted, pillar4Weighted]

  const downloadTranscript = async () => {
    // Check if running locally
    const isLocal = window.location.hostname === 'localhost' || 
                   window.location.hostname === '127.0.0.1' || 
                   window.location.hostname.includes('192.168') ||
                   window.location.port !== ''
    
    if (!isLocal) {
      alert('Transcript download is only available when running locally. Please use your browser\'s print function (Ctrl+P) and select "Save as PDF".')
      return
    }

    try {
      const element = document.getElementById('transcript-content')
      if (!element) {
        alert('Transcript content not found')
        return
      }

      // Get just the transcript card content, not the container
      const transcriptCard = element.cloneNode(true)
      
      // Create a clean HTML structure for PDF that utilizes full page
      const htmlContent = `
        <!DOCTYPE html>
        <html>
        <head>
          <meta charset="utf-8">
          <title>NICHE Official Transcript - ${recipientName}</title>
          <style>
            ${styles}
            @page {
              size: A4 portrait;
              margin: 0;
            }
            body {
              margin: 0;
              padding: 0;
              width: 210mm;
              height: 297mm;
              display: flex;
              justify-content: center;
              align-items: stretch;
              background: white;
            }
            #transcript-content {
              width: 100%;
              height: 100%;
              display: flex;
              flex-direction: column;
              align-items: center;
              justify-content: space-evenly;
              padding: 1.5% 4% 1.5%;
              box-sizing: border-box;
              background-color: #FAF9F6;
              overflow: hidden;
              gap: 8px;
            }
          </style>
        </head>
        <body>
          ${transcriptCard.outerHTML}
        </body>
        </html>
      `

      // Send to Puppeteer service for PDF generation
      const response = await fetch('http://localhost:3001/generate-pdf', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          html: htmlContent,
          filename: `${recipientName.replace(/\s+/g, '_')}_NICHE_Official_Transcript.pdf`,
          options: {
            format: 'A4',
            landscape: false,
            printBackground: true,
            margin: { top: '0mm', bottom: '0mm', left: '0mm', right: '0mm' },
            preferCSSPageSize: true,
            width: '210mm',
            height: '297mm',
            scale: 1.0
          }
        })
      })
      
      if (response.ok) {
        const blob = await response.blob()
        const url = window.URL.createObjectURL(blob)
        const a = document.createElement('a')
        a.href = url
        a.download = `${recipientName.replace(/\s+/g, '_')}_NICHE_Official_Transcript.pdf`
        a.click()
        window.URL.revokeObjectURL(url)
        
        console.log('Official Transcript PDF downloaded successfully')
      } else {
        const errorData = await response.json()
        throw new Error(errorData.details || 'Transcript generation failed')
      }
    } catch (error) {
      console.error('Transcript generation failed:', error)
      alert(`Transcript generation failed: ${error.message}. Make sure the PDF service is running on localhost:3001`)
    }
  }

  return (
    <>
      <style>{styles}</style>
      <div className="fixed inset-0 bg-black bg-opacity-75 flex items-center justify-center z-50">
        <div className="relative w-full h-full max-w-4xl max-h-[95vh] overflow-auto">
          
          {/* Close Button and Download - Fixed position */}
          <div className="absolute top-4 left-4 right-4 flex justify-between z-20">
            <button
              onClick={downloadTranscript}
              className="flex items-center gap-2 bg-[#c5a059] text-white px-4 py-2 rounded-lg hover:bg-[#b8944f] transition-colors shadow-lg"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
              </svg>
              Download Transcript
            </button>
            <button
              onClick={onClose}
              className="text-white hover:text-gray-300 text-3xl font-bold bg-black bg-opacity-50 rounded-full w-10 h-10 flex items-center justify-center shadow-lg"
            >
              ×
            </button>
          </div>

          {/* Transcript - A4 Portrait */}
          <div style={{ minHeight:"100vh", width:"100%", background:"#1a1a1a", display:"flex", justifyContent:"center", alignItems:"flex-start", padding:"40px 16px", boxSizing:"border-box" }}>
            <div style={{ width:"100%", maxWidth:794, margin:"0 auto", padding:"8px 16px" }}>

              {/* Transcript card — A4-portrait aspect ratio */}
              <div className="transcript-bg" style={{
                position:"relative",
                width:"100%",
                aspectRatio:"0.707", // A4 portrait ratio
                display:"flex",
                flexDirection:"column",
                alignItems:"center",
                justifyContent:"flex-start",
                gap:"12px",
                padding:"3% 6% 3%",
                boxSizing:"border-box",
                overflow:"hidden"
              }} id="transcript-content">

                {/* Content without border */}

                {/* ── HEADER ── */}
                <div style={{ textAlign:"center", zIndex:10, width:"100%", marginTop:"20px", marginBottom:"8px", display:"flex", flexDirection:"column", alignItems:"center" }}>
                  <h1 className="font-cinzel" style={{ fontSize:"clamp(20px,3.2vw,32px)", color:"#000", fontWeight:700, letterSpacing:"0.1em", lineHeight:1.1, margin:0, marginBottom:"8px" }}>
                    OFFICIAL TRANSCRIPT
                  </h1>
                  <p className="font-poppins" style={{ fontSize:"clamp(6px,0.7vw,9px)", letterSpacing:"0.2em", color:"#000", textTransform:"uppercase", margin:0 }}>
                    Nestara Institute of Care and Hospitality Excellence
                  </p>
                </div>

                {/* ── STUDENT INFO ── */}
                <div style={{ zIndex:10, width:"100%", marginBottom:"8px", marginTop:"0px", display:"flex", justifyContent:"center", alignItems:"center", gap:"20px" }}>
                  {/* Logo */}
                  <div style={{ display:"flex", justifyContent:"center", alignItems:"center" }}>
                    <img 
                      src={logoBase64} 
                      alt="NICHE Logo" 
                      style={{ 
                        height:"90px",
                        width:"auto",
                        objectFit:"contain" 
                      }} 
                    />
                  </div>
                  
                  {/* Text */}
                  <div style={{ textAlign:"left", display:"flex", flexDirection:"column", justifyContent:"center" }}>
                    <h2 className="font-playfair" style={{ fontWeight:700, fontSize:"clamp(18px,2.4vw,28px)", color:"#000", marginBottom:"8px", letterSpacing:"0.02em", lineHeight:1.1, margin:0, marginBottom:"8px" }}>
                      {recipientName}
                    </h2>
                    <div className="font-poppins" style={{ fontSize:"clamp(7px,0.8vw,10px)", color:"#000", lineHeight:1.3 }}>
                      <div style={{ whiteSpace:"nowrap" }}><span className="font-cinzel" style={{ color:"#d95637", fontWeight:600 }}>{course}</span></div>
                      <div>Cohort: {cohortNumber} | Graduation: {graduationDate}</div>
                      <div>Final Grade: <span className="font-cinzel" style={{ color:"#d95637", fontWeight:700 }}>{tier}</span> ({Math.round(finalScore)}/100)</div>
                    </div>
                  </div>
                </div>

                {/* ── DETAILED BREAKDOWN ── */}
                <div style={{ width:"100%", maxWidth:600, zIndex:10, marginTop:"8px" }}>
                  <h3 className="font-cinzel" style={{ textAlign:"center", fontSize:"clamp(10px,1.1vw,14px)", fontWeight:700, color:"#000", letterSpacing:"0.1em", marginBottom:"16px" }}>
                    Professional Competency Pillars
                  </h3>
                  
                  {pillars.map((pillar, pillarIndex) => (
                    <div key={pillarIndex} style={{ marginBottom:"16px", border:"1px solid #d95637", borderRadius:"4px", overflow:"hidden" }}>
                      {/* Pillar Header */}
                      <div style={{ backgroundColor:"rgba(217, 86, 55, 0.1)", padding:"8px 12px", borderBottom:"1px solid #d95637" }}>
                        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                          <span className="font-poppins" style={{ fontSize:"clamp(8px,0.9vw,11px)", fontWeight:600, color:"#000" }}>
                            {pillar.name}
                          </span>
                          <span className="font-playfair" style={{ fontSize:"clamp(9px,1vw,12px)", fontWeight:700, color:"#d95637" }}>
                            {weightedScores[pillarIndex]?.toFixed(1)}/{pillar.maxWeighted}
                          </span>
                        </div>
                      </div>
                      
                      {/* Sub-pillars */}
                      <div style={{ padding:"8px 12px" }}>
                        {pillar.subPillars.map((subPillar, subIndex) => {
                          // Get actual sub-pillar score from props
                          const actualScore = subPillarScores[subPillar.key] || 0
                          
                          return (
                            <div key={subIndex} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"4px 0", borderBottom: subIndex < pillar.subPillars.length - 1 ? "1px solid #eee" : "none" }}>
                              <span className="font-poppins" style={{ fontSize:"clamp(7px,0.8vw,9px)", color:"#666" }}>
                                {subPillar.name}
                              </span>
                              <span className="font-poppins" style={{ fontSize:"clamp(7px,0.8vw,9px)", fontWeight:500, color:"#000" }}>
                                {actualScore}/{subPillar.maxScore}
                              </span>
                            </div>
                          )
                        })}
                      </div>
                    </div>
                  ))}

                </div>

                {/* ── FOOTER ── */}
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", width:"100%", maxWidth:600, zIndex:10, marginTop:"8px", gap:"20px" }}>
                  
                  {/* Grading Scale Table */}
                  <div style={{ flex:1, display:"flex", justifyContent:"flex-start" }}>
                    <table style={{ border:"1px solid rgba(217, 86, 55, 0.3)", borderCollapse:"collapse", fontSize:"clamp(7px,0.8vw,9px)" }}>
                      <thead>
                        <tr>
                          <th className="font-poppins" style={{ border:"1px solid #d95637", padding:"4px 6px", backgroundColor:"rgba(217, 86, 55, 0.15)", fontWeight:600, color:"#d95637", textAlign:"center" }}>MASTER</th>
                          <th className="font-poppins" style={{ border:"1px solid #d95637", padding:"4px 6px", backgroundColor:"rgba(217, 86, 55, 0.15)", fontWeight:600, color:"#d95637", textAlign:"center" }}>DISTINGUISHED</th>
                          <th className="font-poppins" style={{ border:"1px solid #d95637", padding:"4px 6px", backgroundColor:"rgba(217, 86, 55, 0.15)", fontWeight:600, color:"#d95637", textAlign:"center" }}>EXCEPTIONAL</th>
                          <th className="font-poppins" style={{ border:"1px solid #d95637", padding:"4px 6px", backgroundColor:"rgba(217, 86, 55, 0.15)", fontWeight:600, color:"#d95637", textAlign:"center" }}>EXCELLENT</th>
                        </tr>
                      </thead>
                      <tbody>
                        <tr>
                          <td className="font-poppins" style={{ border:"1px solid #d95637", padding:"4px 6px", color:"#666", textAlign:"center" }}>95+</td>
                          <td className="font-poppins" style={{ border:"1px solid #d95637", padding:"4px 6px", color:"#666", textAlign:"center" }}>90-94</td>
                          <td className="font-poppins" style={{ border:"1px solid #d95637", padding:"4px 6px", color:"#666", textAlign:"center" }}>80-89</td>
                          <td className="font-poppins" style={{ border:"1px solid #d95637", padding:"4px 6px", color:"#666", textAlign:"center" }}>70-79</td>
                        </tr>
                      </tbody>
                    </table>
                  </div>

                  {/* Lead Trainer Signature */}
                  <div style={{ flex:1, display:"flex", justifyContent:"flex-end", alignItems:"flex-start", paddingTop:"2px" }}>
                    <div style={{ textAlign:"right" }}>
                      <div style={{ borderBottom:"2px solid #d95637", width:"180px", height:"25px", marginBottom:"1px" }}></div>
                      <span className="font-poppins" style={{ fontSize:"clamp(8px,0.9vw,11px)", color:"#000", fontWeight:600 }}>
                        Lead Trainer, NICHE
                      </span>
                    </div>
                  </div>
                </div>

              </div>
            </div>
          </div>
        </div>
      </div>
    </>
  )
}

export default NicheTranscript